import{_ as o,o as i,c as r,ae as t}from"./chunks/framework.CB71nIlf.js";const p=JSON.parse('{"title":"Technical Support","description":"","frontmatter":{},"headers":[],"relativePath":"en/7-technical-support/index.md","filePath":"en/7-technical-support/index.md"}'),a={name:"en/7-technical-support/index.md"};function n(l,e,s,c,u,h){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="technical-support" tabindex="-1">Technical Support <a class="header-anchor" href="#technical-support" aria-label="Permalink to &quot;Technical Support&quot;">​</a></h1><p>Need help? We&#39;re here to support you.</p><h2 id="contact-information" tabindex="-1">Contact Information <a class="header-anchor" href="#contact-information" aria-label="Permalink to &quot;Contact Information&quot;">​</a></h2><h3 id="technical-support-email" tabindex="-1">Technical Support Email <a class="header-anchor" href="#technical-support-email" aria-label="Permalink to &quot;Technical Support Email&quot;">​</a></h3><p><strong><a href="mailto:support@cogniand.com" target="_blank" rel="noreferrer">support@cogniand.com</a></strong></p><h3 id="feedback-channels" tabindex="-1">Feedback Channels <a class="header-anchor" href="#feedback-channels" aria-label="Permalink to &quot;Feedback Channels&quot;">​</a></h3><ul><li>Platform feedback feature (submit feedback in personal center after logging in)</li><li>GitHub Issues (if project is open source)</li><li>Technical support forum</li></ul><h3 id="response-time" tabindex="-1">Response Time <a class="header-anchor" href="#response-time" aria-label="Permalink to &quot;Response Time&quot;">​</a></h3><ul><li>Weekdays: Response within 24 hours</li><li>Weekends and holidays: Response within 48 hours</li><li>Urgent issues: Please mark &quot;Urgent&quot; in email subject</li></ul><h2 id="when-submitting-issues-please-provide" tabindex="-1">When Submitting Issues, Please Provide <a class="header-anchor" href="#when-submitting-issues-please-provide" aria-label="Permalink to &quot;When Submitting Issues, Please Provide&quot;">​</a></h2><p>To resolve issues faster, please provide the following information:</p><h3 id="_1-problem-description" tabindex="-1">1. Problem Description <a class="header-anchor" href="#_1-problem-description" aria-label="Permalink to &quot;1. Problem Description&quot;">​</a></h3><ul><li>Detailed description of the problem</li><li>Time and frequency of occurrence</li></ul><h3 id="_2-steps-to-reproduce" tabindex="-1">2. Steps to Reproduce <a class="header-anchor" href="#_2-steps-to-reproduce" aria-label="Permalink to &quot;2. Steps to Reproduce&quot;">​</a></h3><ul><li>Detailed steps to reproduce the problem</li><li>Expected result vs actual result</li></ul><h3 id="_3-environment-information" tabindex="-1">3. Environment Information <a class="header-anchor" href="#_3-environment-information" aria-label="Permalink to &quot;3. Environment Information&quot;">​</a></h3><ul><li>Operating system (Windows/Mac/Linux)</li><li>Browser type and version</li><li>Account role (subject/experimenter/admin)</li></ul><h3 id="_4-error-information" tabindex="-1">4. Error Information <a class="header-anchor" href="#_4-error-information" aria-label="Permalink to &quot;4. Error Information&quot;">​</a></h3><ul><li>Complete error message</li><li>Browser console error messages (if any)</li><li>Screenshots or screen recordings (if applicable)</li></ul><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><p>Before contacting us, we recommend checking:</p><ul><li><a href="/cogniand-manual.github.io/en/1-FAQ/">FAQ</a> - Quick answers to most common questions</li><li><a href="/cogniand-manual.github.io/en/6-troubleshooting/">Troubleshooting</a> - Technical problem troubleshooting</li><li><a href="/cogniand-manual.github.io/en/3-subject-manual/">Subject Manual</a> - Subject feature guide</li><li><a href="/cogniand-manual.github.io/en/2-experimenter-manual/">Experimenter Manual</a> - Experimenter feature guide</li></ul><h2 id="other-resources" tabindex="-1">Other Resources <a class="header-anchor" href="#other-resources" aria-label="Permalink to &quot;Other Resources&quot;">​</a></h2><ul><li><strong>Platform Website</strong>: <a href="https://cogniand.com" target="_blank" rel="noreferrer">https://cogniand.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/cogniand" target="_blank" rel="noreferrer">https://github.com/cogniand</a></li><li><strong>Documentation Center</strong>: This manual website</li></ul><h2 id="how-to-get-browser-console-errors" tabindex="-1">How to Get Browser Console Errors <a class="header-anchor" href="#how-to-get-browser-console-errors" aria-label="Permalink to &quot;How to Get Browser Console Errors&quot;">​</a></h2><p>If you encounter technical issues, viewing browser console can help diagnose:</p><p><strong>Open Console</strong>:</p><ul><li>Chrome/Edge: <code>F12</code> or <code>Ctrl + Shift + I</code></li><li>Firefox: <code>F12</code> or <code>Ctrl + Shift + K</code></li><li>Safari: <code>Cmd + Option + I</code> (need to enable developer menu in preferences first)</li></ul><p><strong>View Error Messages</strong>:</p><ol><li>Open console</li><li>Switch to &quot;Console&quot; tab</li><li>Look for red error messages</li><li>Take screenshot and send to technical support</li></ol><h2 id="security-vulnerability-reporting" tabindex="-1">Security Vulnerability Reporting <a class="header-anchor" href="#security-vulnerability-reporting" aria-label="Permalink to &quot;Security Vulnerability Reporting&quot;">​</a></h2><p>If you discover a security vulnerability on the platform, please:</p><ol><li><p><strong>Do Not Publicly Disclose</strong></p><ul><li>Do not publish vulnerability information in public channels</li><li>Avoid malicious exploitation</li></ul></li><li><p><strong>Contact Technical Team</strong></p><ul><li>Send email to: <a href="mailto:security@cogniand.com" target="_blank" rel="noreferrer">security@cogniand.com</a></li><li>Describe vulnerability situation in detail</li><li>Provide reproduction steps (if any)</li></ul></li><li><p><strong>Wait for Response</strong></p><ul><li>We will respond within 24 hours</li><li>Will fix promptly after confirming vulnerability</li><li>Will notify you after fix</li></ul></li></ol><p><strong>Thank you for your contribution!</strong></p><h2 id="feedback-and-suggestions" tabindex="-1">Feedback and Suggestions <a class="header-anchor" href="#feedback-and-suggestions" aria-label="Permalink to &quot;Feedback and Suggestions&quot;">​</a></h2><p>We welcome your feedback and suggestions to help us improve the platform:</p><h3 id="how-to-submit-feedback" tabindex="-1">How to Submit Feedback <a class="header-anchor" href="#how-to-submit-feedback" aria-label="Permalink to &quot;How to Submit Feedback&quot;">​</a></h3><ol><li><p><strong>Platform Feedback Feature</strong></p><ul><li>Log in to your account</li><li>Go to personal center</li><li>Click &quot;Submit Feedback&quot;</li><li>Fill in feedback content</li><li>Submit</li></ul></li><li><p><strong>Email Feedback</strong></p><ul><li>Send email to: <a href="mailto:feedback@cogniand.com" target="_blank" rel="noreferrer">feedback@cogniand.com</a></li><li>Describe your suggestions or issues</li><li>We will carefully review every feedback</li></ul></li><li><p><strong>GitHub Issues</strong></p><ul><li>If project is open source</li><li>Submit issue on GitHub</li><li>Participate in community discussions</li></ul></li></ol><h3 id="what-feedback-we-need" tabindex="-1">What Feedback We Need <a class="header-anchor" href="#what-feedback-we-need" aria-label="Permalink to &quot;What Feedback We Need&quot;">​</a></h3><ul><li>Feature suggestions</li><li>User experience improvements</li><li>Bug reports</li><li>Documentation improvements</li><li>Any other suggestions</li></ul><hr><p><strong>We&#39;re committed to providing you with the best support!</strong></p><p>If you have any questions or need help, please don&#39;t hesitate to contact us. We&#39;re here to help you have the best experience on the CogniAND platform.</p>',43)])])}const m=o(a,[["render",n]]);export{p as __pageData,m as default};
